/*******

Return CQP_INCEPTION_DATE formatted as "DD-MMM-YYYY"

By Adriana Centellas
*/
const raw = this._parent.CQP_INCEPTION_DATE;

if (!raw) {
return "";
}

// Convert to Date
const date = new Date(raw);

// Array of month abbreviations
const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun",
"Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

// Extract formatted parts
const day = String(date.getDate()).padStart(2, "0");
const month = months[date.getMonth()];
const year = date.getFullYear();

// Return formatted
return day + '-' + month + '-' + year;

/********
 * CQP_EXPIRATION_DATE formatted as "DD-MMM-YYYY"
 * By Adriana Centellas
 */

const raw = this._parent.CQP_EXPIRATION_DATE;

if (!raw) {
  return "";
}

// Convert to Date
const date = new Date(raw);

// Month abbreviations
const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun",
                "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

// Extract parts
const day   = String(date.getDate()).padStart(2, "0");
const month = months[date.getMonth()];
const year  = date.getFullYear();

// Return formatted
return day + '-' + month + '-' + year;

