/****
 * '=CQP_GWP_USD-(CQP_GWP_USD*(CQP_BROKERAGE_COMISSION+CQP_TAX))
 * By Adriana Centellas
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_GWP_USD) - (safeNumber(this.CQP_GWP_USD) * ((safeNumber(this.CQP_BROKERAGE_COMISSION)/100) + (safeNumber(this.CQP_TAX)/100)));

/******
 * =CQP_CLAIM_USD/CQP_GWP_USD
 * By Adriana Centellas
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

return safeNumber((safeNumber(this.CQP_CLAIM_USD) / safeNumber(this.CQP_GWP_USD)) * 100);

